#include<bits/stdc++.h>
using namespace std;

const int N = 1e3 + 5;
const double eps = 1e-8; 

int n, m;
int f[N];
double dis[N];
int cnt[N];
bool vis[N];

struct Edge {
    int v, w;
};
vector<Edge> e[N];

bool SPFA(double mid) {
    queue<int> q;
    for (int i = 1; i <= n; i++) {
        dis[i] = 0;
        cnt[i] = 0;
        vis[i] = true;
        q.push(i);
    }

    while (!q.empty()) {
        int u = q.front();
        q.pop();
        vis[u] = false;

        for (auto edge : e[u]) {
            int v = edge.v;
            int w = edge.w;
            double new_weight = mid * w - f[u];  // 边权: mid * 时间 - 乐趣值

            if (dis[v] > dis[u] + new_weight + eps) {  // 添加eps避免浮点误差
                dis[v] = dis[u] + new_weight;
                cnt[v] = cnt[u] + 1;

                if (cnt[v] >= n) return true;

                if (!vis[v]) {
                    vis[v] = true;
                    q.push(v);
                }
            }
        }
    }
    return false;
}

int main() {
    cin.tie(0)->sync_with_stdio(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++)
        cin >> f[i];
    for (int i = 1; i <= m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        e[u].push_back({v, w});
    }

    double l = 0, r = 1000;
    while (r - l > eps) {
        double mid = (l + r) / 2;
        if (SPFA(mid)) {
            l = mid;
        } else {
            r = mid;
        }
    }

    if (l < eps) {  
        printf("0.00\n");
    } else {
        printf("%.2lf\n", l);
    }

    return 0;
}
